#include<bits/stdc++.h>
using namespace std;
int v[53][53];
int main(){
    int n;
    cin>>n;
    for(int i=1;i<=52;i++) for(int j=1;j<=52;j ++) v[i][j]=1e8;
    for(int i=1;i<=n;i++){
        char a,b;
        int c,a1,b1;
        cin>>a>>b>>c;
        if(a>='A'&&a<='Z'){
           a1=a-'A'+1; 
        }else{
            a1=a-'a'+1+26;
        }
        if(b>='A'&&b<='Z'){
           b1=b-'A'+1; 
        }else{
            b1=b-'a'+1+26;
        }
        v[a1][b1]=min( v[a1][b1],c);
        v[b1][a1]=min( v[b1][a1],c);
    }
    for(int i=1;i<=52;i++) for(int j=1;j<=52;j ++) for(int k=1;k<=52;k++) if(v[j][k]>v[j][i]+v[i][k]) v[j][k]=v[j][i]+v[i][k];
    int minn=1e8;
    char duan;
    for(int i=1;i<=25;i++)  {if(minn>v[i][26]) {minn=v[i][26];duan=i+'A'-1;}}
    cout<<duan<<" "<<minn;
    return 0;
}
